# filesystem.py
# ── WHY THIS MODULE ──────────────────────────────────────────────────────────
# The orchestrator. It owns the root and the current directory and runs every
# command. The clean version has ZERO lock code — concurrency lives in the
# ThreadSafeFileSystem subclass, which overrides one hook.
from __future__ import annotations

import threading
from contextlib import contextmanager
from typing import Iterator, List, Optional, Tuple

from models import (
    Node,
    NodeType,
    InvalidPathError,
)
from strategies import AmbiguityResolutionStrategy, FirstMatchStrategy

MAX_PATH_LEN = 100


class FileSystem:
    def __init__(self, strategy: Optional[AmbiguityResolutionStrategy] = None) -> None:
        # Root has an empty name and no parent; pwd builds "/" from that.
        self._root = Node(name="", type=NodeType.DIR, parent=None)
        self._cwd = self._root
        self._strategy = strategy or FirstMatchStrategy()

    # ── lock hook (Template Method) ───────────────────────────────────────────
    # WHY: does nothing here, so the clean core has no locking at all. The
    #      thread-safe subclass replaces just this method with a real lock.
    @contextmanager
    def _lock(self) -> Iterator[None]:
        yield

    # ── validation at the public boundary ─────────────────────────────────────
    @staticmethod
    def _split(path: str) -> Tuple[bool, List[str]]:
        if not path:
            raise InvalidPathError("empty path")
        if len(path) > MAX_PATH_LEN:
            raise InvalidPathError(f"path exceeds {MAX_PATH_LEN} characters")
        is_absolute = path.startswith("/")
        comps = [c for c in path.split("/") if c != ""]
        for c in comps:
            # WHY: '*' is only a wildcard as a WHOLE component. A directory name
            #      cannot contain '*', so 'a*b' is rejected before any mutation.
            if "*" in c and c != "*":
                raise InvalidPathError(f"invalid component '{c}': '*' must stand alone")
        return is_absolute, comps

    # ── wildcard resolution: backtracking DFS as a lazy generator ─────────────
    # 🎙️ "This is the heart. I yield every directory the path could land on, in
    #     priority order, and back out of dead ends automatically."
    def _resolve(self, node: Node, comps: List[str]) -> Iterator[Node]:
        if not comps:
            if node.is_dir:
                yield node
            return
        head, rest = comps[0], comps[1:]
        for cand in self._candidates(node, head):
            yield from self._resolve(cand, rest)  # WHY: DFS; bad branches yield nothing

    def _candidates(self, node: Node, comp: str) -> Iterator[Node]:
        if comp == ".":
            yield node
        elif comp == "..":
            yield node.parent or node  # WHY: '..' at root stays at root
        elif comp == "*":
            # WHY: '*' matches CHILD directories only, yielded alphabetically so
            #      the choice is deterministic (/foo/* -> /foo/bar).
            for name in sorted(node.children):
                child = node.children[name]
                if child.is_dir:
                    yield child
        else:
            child = node.children.get(comp)
            if child is not None and child.is_dir:
                yield child

    # ── public API ────────────────────────────────────────────────────────────
    def mkdir(self, path: str) -> bool:
        with self._lock():
            is_absolute, comps = self._split(path)
            if "*" in comps:
                raise InvalidPathError("mkdir does not support '*'")
            node = self._root if is_absolute else self._cwd
            for name in comps:
                if name == ".":
                    continue
                if name == "..":
                    node = node.parent or node
                    continue
                child = node.children.get(name)
                if child is None:
                    child = Node(name=name, type=NodeType.DIR, parent=node)
                    node.children[name] = child
                elif not child.is_dir:
                    # WHY: a file already sits here — cannot turn it into a dir.
                    return False
                node = child
            return True

    def pwd(self) -> str:
        with self._lock():
            names: List[str] = []
            node = self._cwd
            while node.parent is not None:  # WHY: walk up to root via parent pointers
                names.append(node.name)
                node = node.parent
            return "/" + "/".join(reversed(names))

    def cd(self, path: str) -> None:
        with self._lock():
            is_absolute, comps = self._split(path)
            start = self._root if is_absolute else self._cwd
            matches = self._resolve(start, comps)
            target = self._strategy.choose(matches)  # raises on none / (strict) many
            # WHY: only mutate cwd AFTER we have a valid target — a failed cd
            #      leaves the current directory untouched.
            self._cwd = target

    def touch(self, path: str) -> bool:
        # Not in the core spec, but it's what makes mkdir's "file blocks" case
        # real and testable. Creates missing parent dirs, then a file leaf.
        with self._lock():
            is_absolute, comps = self._split(path)
            if "*" in comps:
                raise InvalidPathError("touch does not support '*'")
            if not comps:
                raise InvalidPathError("cannot create a file at root")
            node = self._root if is_absolute else self._cwd
            *parents, last = comps
            for name in parents:
                if name == ".":
                    continue
                if name == "..":
                    node = node.parent or node
                    continue
                child = node.children.get(name)
                if child is None:
                    child = Node(name=name, type=NodeType.DIR, parent=node)
                    node.children[name] = child
                elif not child.is_dir:
                    return False
                node = child
            if last in (".", ".."):
                raise InvalidPathError("invalid file name")
            if last in node.children:
                return False  # something already exists here
            node.children[last] = Node(name=last, type=NodeType.FILE, parent=node)
            return True


# ── thread-safe variant: overrides ONLY the lock hook ─────────────────────────
class ThreadSafeFileSystem(FileSystem):
    def __init__(self, strategy: Optional[AmbiguityResolutionStrategy] = None) -> None:
        super().__init__(strategy)
        # WHY: RLock (not Lock) so a guarded method could safely call another
        #      guarded method without deadlocking on itself.
        self._rlock = threading.RLock()

    @contextmanager
    def _lock(self) -> Iterator[None]:
        with self._rlock:
            yield
